import { type CSSProperties } from 'react';
import type { ThemeConfig } from '@content/player-core';
import type { OutlineItem } from '../hooks/usePdfOutline';

interface Props {
  /** true = renders as permanent left sidebar (part of flex layout) */
  isDesktop: boolean;
  /** controls overlay visibility on phone/tablet — ignored on desktop */
  isOpen: boolean;
  outline: OutlineItem[];
  currentPage: number;
  onNavigate: (page: number) => void;
  onClose: () => void;
  onExit: () => void;
  theme?: ThemeConfig;
}

export function DrawerMenu({
  isDesktop,
  isOpen,
  outline,
  currentPage,
  onNavigate,
  onClose,
  onExit,
  theme,
}: Props) {
  const accent = theme?.primary ?? '#1a73e8';
  const bg = '#1a1a2e';

  // The last outline entry whose pageNumber ≤ currentPage is the active chapter
  const activeIndex = outline.reduce(
    (acc, item, idx) => (item.pageNumber <= currentPage ? idx : acc),
    -1,
  );

  const panel = (
    <div style={panelStyle(bg, isDesktop)}>
      {/* Header row */}
      <div style={panelHeader}>
        <span style={panelTitle}>CONTENTS</span>
        {!isDesktop && (
          <button style={closeBtnStyle} onClick={onClose} aria-label="Close menu">
            ✕
          </button>
        )}
      </div>

      {/* Chapter list */}
      <nav style={chapterListStyle}>
        {outline.length === 0 ? (
          <span style={emptyNoteStyle}>No outline available</span>
        ) : (
          outline.map((item, idx) => (
            <button
              key={idx}
              style={{
                ...chapterItemStyle,
                background: idx === activeIndex ? `${accent}22` : 'none',
                color: idx === activeIndex ? accent : 'rgba(255,255,255,0.82)',
                fontWeight: idx === activeIndex ? 600 : 400,
                borderLeft:
                  idx === activeIndex
                    ? `3px solid ${accent}`
                    : '3px solid transparent',
              }}
              onClick={() => {
                onNavigate(item.pageNumber);
                if (!isDesktop) onClose();
              }}
            >
              <span style={chapterNumStyle}>{idx + 1}</span>
              <span style={chapterLabelStyle}>{item.title}</span>
            </button>
          ))
        )}
      </nav>

      {/* Exit */}
      <div style={exitSectionStyle}>
        <button style={{ ...exitBtnStyle, color: accent }} onClick={onExit}>
          <span style={{ fontSize: 16, lineHeight: 1 }}>⎋</span>
          Exit
        </button>
      </div>
    </div>
  );

  if (isDesktop) return panel;

  if (!isOpen) return null;

  return (
    <>
      <div style={backdropStyle} onClick={onClose} aria-hidden />
      <div style={overlayStyle(bg)} role="dialog" aria-modal aria-label="Contents menu">
        {panel}
      </div>
    </>
  );
}

// ── Styles ────────────────────────────────────────────────────────────────────

const panelStyle = (bg: string, isDesktop: boolean): CSSProperties => ({
  width: isDesktop ? 220 : '100%',
  height: '100%',
  background: bg,
  display: 'flex',
  flexDirection: 'column',
  borderRight: isDesktop ? '1px solid rgba(255,255,255,0.08)' : 'none',
  flexShrink: 0,
});

const panelHeader: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'space-between',
  padding: '14px 16px 10px',
  borderBottom: '1px solid rgba(255,255,255,0.08)',
  flexShrink: 0,
};

const panelTitle: CSSProperties = {
  color: 'rgba(255,255,255,0.45)',
  fontSize: 11,
  fontWeight: 700,
  letterSpacing: '0.08em',
  textTransform: 'uppercase',
  fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif',
};

const closeBtnStyle: CSSProperties = {
  background: 'none',
  border: 'none',
  color: 'rgba(255,255,255,0.55)',
  fontSize: 16,
  cursor: 'pointer',
  padding: '4px 6px',
  borderRadius: 4,
  lineHeight: 1,
};

const chapterListStyle: CSSProperties = {
  flex: 1,
  overflowY: 'auto',
  padding: '6px 0',
  display: 'flex',
  flexDirection: 'column',
};

const chapterItemStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'flex-start',
  gap: 10,
  width: '100%',
  padding: '10px 16px',
  border: 'none',
  cursor: 'pointer',
  textAlign: 'left',
  fontSize: 13,
  fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif',
  lineHeight: 1.4,
  transition: 'background 0.15s',
};

const chapterNumStyle: CSSProperties = {
  flexShrink: 0,
  opacity: 0.5,
  fontSize: 12,
  minWidth: 16,
  marginTop: 1,
};

const chapterLabelStyle: CSSProperties = {
  flex: 1,
};

const emptyNoteStyle: CSSProperties = {
  padding: '16px',
  color: 'rgba(255,255,255,0.35)',
  fontSize: 12,
  fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif',
};

const exitSectionStyle: CSSProperties = {
  padding: '8px 0',
  borderTop: '1px solid rgba(255,255,255,0.08)',
  flexShrink: 0,
};

const exitBtnStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 12,
  width: '100%',
  padding: '12px 20px',
  border: 'none',
  background: 'none',
  fontSize: 14,
  fontWeight: 600,
  fontFamily: '-apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif',
  cursor: 'pointer',
  textAlign: 'left',
};

const backdropStyle: CSSProperties = {
  position: 'absolute',
  inset: 0,
  background: 'rgba(0,0,0,0.5)',
  zIndex: 40,
};

const overlayStyle = (bg: string): CSSProperties => ({
  position: 'absolute',
  top: 0,
  left: 0,
  bottom: 0,
  width: 280,
  background: bg,
  zIndex: 50,
  boxShadow: '4px 0 24px rgba(0,0,0,0.55)',
  display: 'flex',
  flexDirection: 'column',
});
