import { useState, type CSSProperties } from 'react';
import type { ThemeConfig } from '@content/player-core';

interface Props {
  isPhone: boolean;
  isPlaying: boolean;
  currentTime: number;
  duration: number;
  volume: number;
  muted: boolean;
  playbackRate: number;
  isFullscreen: boolean;
  theme?: ThemeConfig;
  onPlayPause: () => void;
  onSeek: (timeSec: number) => void;
  onSkipBack: () => void;
  onSkipForward: () => void;
  onVolumeChange: (vol: number) => void;
  onMuteToggle: () => void;
  onPlaybackRateChange: (rate: number) => void;
  onFullscreen: () => void;
  onRestart: () => void;
}

function fmtTime(sec: number): string {
  if (!isFinite(sec) || isNaN(sec)) return '0:00';
  const m = Math.floor(sec / 60);
  const s = Math.floor(sec % 60);
  return `${m}:${s.toString().padStart(2, '0')}`;
}

const RATES = [0.5, 0.75, 1, 1.25, 1.5, 2];

export function VideoControls({
  isPhone,
  isPlaying,
  currentTime,
  duration,
  volume,
  muted,
  playbackRate,
  isFullscreen,
  theme,
  onPlayPause,
  onSeek,
  onSkipBack,
  onSkipForward,
  onVolumeChange,
  onMuteToggle,
  onPlaybackRateChange,
  onFullscreen,
  onRestart,
}: Props) {
  const accent = theme?.primary ?? '#2980b9';
  const toolbarBg = theme?.toolbar ?? 'rgba(14,14,20,0.97)';
  const [showRateMenu, setShowRateMenu] = useState(false);

  const progress = duration > 0 ? (currentTime / duration) * 100 : 0;
  const volumeDisplay = muted ? 0 : volume;

  const progressBar = (
    <div style={sliderWrap}>
      <input
        type="range"
        min={0}
        max={duration || 100}
        step={0.25}
        value={currentTime}
        onChange={(e) => onSeek(parseFloat(e.target.value))}
        style={progressInput(accent, progress)}
        aria-label="Seek"
      />
    </div>
  );

  if (isPhone) {
    return (
      <div style={phoneBar(toolbarBg)}>
        {/* Time row */}
        <div style={timeRow}>
          <span style={timeLabel}>{fmtTime(currentTime)}</span>
          {progressBar}
          <span style={timeLabel}>{fmtTime(duration)}</span>
        </div>
        {/* Icon row */}
        <div style={iconRow}>
          <IconBtn onClick={onRestart} label="Restart">
            <RestartIcon />
          </IconBtn>
          <IconBtn onClick={onPlayPause} label={isPlaying ? 'Pause' : 'Play'}>
            {isPlaying ? <PauseIcon /> : <PlayIcon />}
          </IconBtn>
          <IconBtn onClick={onSkipBack} label="Skip back 5s">
            <SkipBackIcon />
          </IconBtn>
          <IconBtn onClick={onMuteToggle} label={muted ? 'Unmute' : 'Mute'}>
            {(muted || volume === 0) ? <MuteIcon /> : <VolumeIcon />}
          </IconBtn>
          <IconBtn onClick={onFullscreen} label={isFullscreen ? 'Exit fullscreen' : 'Fullscreen'}>
            {isFullscreen ? <ExitFullscreenIcon /> : <FullscreenIcon />}
          </IconBtn>
        </div>
      </div>
    );
  }

  // Tablet / Desktop
  return (
    <div style={desktopBar(toolbarBg)}>
      {/* Restart */}
      <IconBtn onClick={onRestart} label="Restart">
        <RestartIcon />
      </IconBtn>

      {/* Play / Pause */}
      <IconBtn onClick={onPlayPause} label={isPlaying ? 'Pause' : 'Play'}>
        {isPlaying ? <PauseIcon /> : <PlayIcon />}
      </IconBtn>

      {/* Skip back */}
      <IconBtn onClick={onSkipBack} label="Skip back 5s">
        <SkipBackIcon />
      </IconBtn>

      {/* Skip forward */}
      <IconBtn onClick={onSkipForward} label="Skip forward 5s">
        <SkipFwdIcon />
      </IconBtn>

      {/* Time */}
      <span style={desktopTime}>
        {fmtTime(currentTime)}&nbsp;<span style={{ opacity: 0.4 }}>/</span>&nbsp;{fmtTime(duration)}
      </span>

      {/* Progress */}
      {progressBar}

      {/* Keyboard hints — desktop only */}
      {!isPhone && (
        <span style={kbHint}>
          <kbd style={kbTag}>Space</kbd> play&nbsp;
          <kbd style={kbTag}>← →</kbd> seek
        </span>
      )}

      {/* Volume */}
      <IconBtn onClick={onMuteToggle} label={muted ? 'Unmute' : 'Mute'}>
        {(muted || volume === 0) ? <MuteIcon /> : <VolumeIcon />}
      </IconBtn>
      <input
        type="range" min={0} max={1} step={0.05} value={volumeDisplay}
        onChange={(e) => onVolumeChange(parseFloat(e.target.value))}
        style={volumeSlider(accent, volumeDisplay * 100)}
        aria-label="Volume"
      />

      {/* Playback rate */}
      <div style={{ position: 'relative' }}>
        <button style={rateBtn} onClick={() => setShowRateMenu((v) => !v)}
          aria-label="Playback speed">
          {playbackRate === 1 ? '1×' : `${playbackRate}×`}
        </button>
        {showRateMenu && (
          <div style={rateMenu(toolbarBg)}>
            {RATES.map((r) => (
              <button
                key={r}
                style={{ ...rateItem, color: r === playbackRate ? accent : '#fff' }}
                onClick={() => { onPlaybackRateChange(r); setShowRateMenu(false); }}
              >
                {r === 1 ? 'Normal' : `${r}×`}
              </button>
            ))}
          </div>
        )}
      </div>

      {/* Fullscreen */}
      <IconBtn onClick={onFullscreen} label={isFullscreen ? 'Exit fullscreen' : 'Fullscreen'}>
        {isFullscreen ? <ExitFullscreenIcon /> : <FullscreenIcon />}
      </IconBtn>
    </div>
  );
}

// ── Icon button helper ──────────────────────────────────────────────────────

function IconBtn({ children, onClick, label }: {
  children: React.ReactNode;
  onClick: () => void;
  label: string;
}) {
  return (
    <button style={iconBtn} onClick={onClick} aria-label={label} title={label}>
      {children}
    </button>
  );
}

