import type { RendererInterface } from '@content/player-core';
import { PdfRenderer }     from '@content/player-renderers-pdf';
import { VideoRenderer }   from '@content/player-renderers-video';
import { EpubRenderer }    from '@content/player-renderers-epub';
import { YouTubeRenderer } from '@content/player-renderers-youtube';
import { H5pRenderer }     from '@content/player-renderers-h5p';

const PDF_MIME_TYPES     = new Set(['application/pdf']);
const VIDEO_MIME_TYPES   = new Set(['video/mp4', 'video/webm', 'video/ogg']);
const EPUB_MIME_TYPES    = new Set(['application/epub', 'application/epub+zip']);
const YOUTUBE_MIME_TYPES = new Set(['video/x-youtube', 'video/youtube']);
const H5P_MIME_TYPES     = new Set([
  'application/vnd.ekstep.h5p-archive',
  'application/h5p',
]);

/**
 * Returns the correct RendererInterface implementation for the given MIME type.
 * Returns null for unsupported types.
 */
export function rendererSelector(mimeType: string): RendererInterface | null {
  if (PDF_MIME_TYPES.has(mimeType))     return new PdfRenderer();
  if (VIDEO_MIME_TYPES.has(mimeType))   return new VideoRenderer();
  if (EPUB_MIME_TYPES.has(mimeType))    return new EpubRenderer();
  if (YOUTUBE_MIME_TYPES.has(mimeType)) return new YouTubeRenderer();
  if (H5P_MIME_TYPES.has(mimeType))     return new H5pRenderer();
  return null;
}
