import type { TelemetryTransport, SunbirdTelemetryEvent } from '../TelemetryService';

export class NoOpTransport implements TelemetryTransport {
  readonly received: SunbirdTelemetryEvent[] = [];

  async send(events: SunbirdTelemetryEvent[]): Promise<void> {
    this.received.push(...events);
    // intentionally no-op — console log for dev visibility
    if (typeof console !== 'undefined') {
      events.forEach((e) => console.debug(`[Telemetry] ${e.eid}`, e));
    }
  }
}
