import { ContentPlayerElement } from './ContentPlayerElement';

interface RegisterOptions {
  tagName?: string;
}

/**
 * Idempotent — safe to call multiple times.
 */
export function registerContentPlayer(options: RegisterOptions = {}): void {
  const tag = options.tagName ?? 'content-player';
  if (customElements.get(tag)) return;
  customElements.define(tag, ContentPlayerElement);
}
