import { createRoot, type Root } from 'react-dom/client';
import React, { createRef } from 'react';
import type { RendererInterface, RendererContext, PlayerEvent } from '@content/player-core';
import { saveProgress } from '@content/player-core';
import { PdfRendererView, type PdfRendererHandle } from './PdfRendererView';

/**
 * PdfRenderer implements RendererInterface.
 * It mounts a React tree via createRoot into whatever container PlayerShell provides.
 */
export class PdfRenderer implements RendererInterface {
  private root: Root | null = null;
  private handleRef = createRef<PdfRendererHandle>();
  private handlers = new Map<PlayerEvent, Set<(payload: unknown) => void>>();
  private context: RendererContext | null = null;
  private saveTimer: ReturnType<typeof setInterval> | null = null;

  on(event: PlayerEvent, handler: (payload: unknown) => void): void {
    if (!this.handlers.has(event)) this.handlers.set(event, new Set());
    this.handlers.get(event)!.add(handler);
  }

  removeAllListeners(): void {
    this.handlers.clear();
  }

  async mount(container: HTMLElement, context: RendererContext): Promise<void> {
    this.context = context;
    this.root = createRoot(container);

    this.root.render(
      React.createElement(PdfRendererView, {
        ref: this.handleRef,
        context,
        onReady: () => this.fire('player:ready', {}),
        onStart: () => this.fire('player:start', {}),
        onProgress: (progress: number, page: number, total: number, visitedPages: number) =>
          this.fire('player:progress', { progress, lastPage: page, totalPages: total, visitedPages }),
        onComplete: () => this.fire('player:complete', {}),
        onError: (message: string) => this.fire('player:error', { message }),
      })
    );

    // Periodically persist page position every 5s
    this.saveTimer = setInterval(() => {
      const page = this.handleRef.current?.getCurrentPage();
      if (page && context.contentId) {
        saveProgress(context.contentId, { pageNumber: page });
      }
    }, 5000);
  }

  async unmount(): Promise<void> {
    if (this.saveTimer) clearInterval(this.saveTimer);

    // Read page number BEFORE unmounting — ref becomes null after unmount
    const page = this.handleRef.current?.getCurrentPage();

    // Unmount React root SYNCHRONOUSLY first, before any await.
    // Effect cleanups are not awaited by React, so the new mount() call
    // arrives immediately after cleanup returns. If we awaited saveProgress
    // first, createRoot() would be called on a container that still has an
    // active root, silently breaking replay.
    this.root?.unmount();
    this.root = null;

    // Async progress save can complete in the background
    if (page && this.context?.contentId) {
      await saveProgress(this.context.contentId, { pageNumber: page });
    }
  }

  getCurrentPosition(): number {
    return this.handleRef.current?.getCurrentPage() ?? 1;
  }

  seek(position: number | string): void {
    const page = typeof position === 'string' ? parseInt(position, 10) : position;
    this.handleRef.current?.goToPage(page);
  }

  getCompletionState(): boolean {
    return this.handleRef.current?.getCompletionState() ?? false;
  }

  private fire(event: PlayerEvent, payload: unknown): void {
    this.handlers.get(event)?.forEach((h) => h(payload));
  }
}
