// ── Renderer contract ──────────────────────────────────────────────────────

export type PlayerEvent =
  | 'player:ready'
  | 'player:start'
  | 'player:progress'
  | 'player:complete'
  | 'player:endscreen'
  | 'player:error'
  | 'player:close';

export interface RendererContext {
  contentId: string;
  playSessionId: string;
  mimeType: string;
  src: string;
  mode: 'online' | 'offline';
  extra: ExtraConfig;
  /** Display name of the content (from metadata.name) */
  contentName?: string;
  /** Learner display name (firstName + lastName from SunbirdContext.userData) */
  userName?: string;
  /** Called when the renderer's own exit button is clicked */
  onExitRequest?: () => void;
  /** Emit a telemetry event scoped to this session */
  emit: (eventName: string, payload: Record<string, unknown>) => void;
}

export interface RendererInterface {
  mount(container: HTMLElement, context: RendererContext): Promise<void>;
  unmount(): Promise<void>;
  getCurrentPosition(): number | string;
  seek(position: number | string): void;
  getCompletionState(): boolean;
  on(event: PlayerEvent, handler: (payload: unknown) => void): void;
  /** Remove all registered event handlers (called before re-mounting on replay) */
  removeAllListeners(): void;
  /** When true, PlayerShell will not render its generic EndScreen — the renderer handles it itself */
  hasOwnEndScreen?: boolean;
}

// ── Sunbird legacy config shape ────────────────────────────────────────────

export interface SunbirdPlayerConfig {
  context: SunbirdContext;
  config?: SunbirdConfig;
  metadata: ContentMetadata;
  data?: unknown;
  extra?: ExtraConfig;
}

export interface SunbirdContext {
  mode?: string;
  pdata?: { id: string; ver: string; pid?: string };
  sid?: string;
  uid?: string;
  did?: string;
  channel?: string;
  cdata?: Array<Record<string, unknown>>;
  tags?: string[];
  contextRollup?: Record<string, string>;
  objectRollup?: Record<string, string>;
  timeDiff?: number;
  userdata?: { firstname?: string; lastname?: string; [key: string]: unknown };
  userData?: { firstName?: string; lastName?: string; [key: string]: unknown };
}

export interface SunbirdConfig {
  showEndPage?: boolean;
  sideMenu?: {
    showExit?: boolean;
    showReplay?: boolean;
    showShare?: boolean;
    showDownload?: boolean;
    showPrint?: boolean;
  };
  plugins?: Array<{ id: string; ver: string; type: string | number }>;
}

export interface ContentMetadata {
  identifier?: string;
  mimeType: string;
  artifactUrl?: string;
  streamingUrl?: string;
  name?: string;
  description?: string;
  contentType?: string;
  language?: string[];
  [key: string]: unknown;
}

// ── Extra / extension config ───────────────────────────────────────────────

export interface ThemeConfig {
  /** Accent colour used for buttons, progress bar, and highlights */
  primary?: string;
  /** Toolbar background colour */
  toolbar?: string;
  /** PDF viewer / page area background colour */
  background?: string;
}

export interface ExtraConfig {
  resume?: ResumeConfig;
  pause?: PauseConfig;
  telemetry?: Partial<TelemetryConfig>;
  pdf?: PdfExtraConfig;
  video?: VideoExtraConfig;
  epub?: EpubExtraConfig;
  h5p?: H5pExtraConfig;
  theme?: ThemeConfig;
}

export interface ResumeConfig {
  enabled: boolean;
  mode: 'auto' | 'prompt' | 'off';
}

export interface PauseConfig {
  onBlur?: boolean;
}

export interface PdfExtraConfig {
  workerSrc?: string;
  /** Page to open when no saved resume progress exists (defaults to 1) */
  startPage?: number;
  /** URL to the CMap files directory (needed for Unicode/multilingual PDFs) */
  cMapUrl?: string;
  /** URL to the standard font data directory (needed for non-embedded fonts) */
  standardFontDataUrl?: string;
}

export interface VideoExtraConfig {
  /** Start from this position in seconds (overridden by resume if enabled) */
  startPosition?: number;
}

export interface EpubExtraConfig {
  /** Initial font size in px (default 18) */
  fontSize?: number;
  /** Initial reading theme: 'light' | 'sepia' | 'dark' (default 'light') */
  readingTheme?: 'light' | 'sepia' | 'dark';
}

export interface H5pExtraConfig {
  /** Base URL where H5P library folders (JS/CSS) are served from.
   *  Defaults to '/h5p-libs' (bundled with the player).
   *  Override when hosting libraries at a custom path or CDN. */
  librariesPath?: string;
}

// ── Normalized internal config ─────────────────────────────────────────────

export interface PlayerInitConfig {
  contentId: string;
  mimeType: string;
  src: string;
  mode: 'online' | 'offline';
  endScreenEnabled: boolean;
  endScreenConfig: EndScreenConfig;
  telemetryConfig: TelemetryConfig;
  extra: ExtraConfig;
  metadata: ContentMetadata;
  context: SunbirdContext;
  iframeEventEnabled: boolean;
  endScreenCapabilityEnabled: boolean;
  /** Display name of the user — built from context.userdata.firstname + lastname */
  userName?: string;
}

export interface EndScreenConfig {
  exitLabel?: string;
  showSessionSummary?: boolean;
  showScore?: boolean;
  autoCloseOnComplete?: boolean;
  showReplay?: boolean;
}

export interface TelemetryConfig {
  endpoint?: string;
  authToken?: string;
  batchSize?: number;
  flushIntervalMs?: number;
  // Sunbird context fields
  pdata?: { id: string; ver: string; pid?: string };
  uid?: string;
  did?: string;
  sid?: string;
  channel?: string;
  rollup?: Record<string, string>;
  objectRollup?: Record<string, string>;
  tags?: string[];
  playerVersion?: string;
  env?: string;
}

// ── Persistence records ────────────────────────────────────────────────────

export interface ProgressRecord {
  contentId: string;
  pageNumber?: number;
  positionMs?: number;
  cfi?: string;
  updatedAt: number;
}

export interface AttemptState {
  contentId: string;
  responses: unknown[];
  score: number;
  currentIndex: number;
  sessionId: string;
}

// ── Type guard ─────────────────────────────────────────────────────────────

export function isSunbirdPlayerConfig(v: unknown): v is SunbirdPlayerConfig {
  if (!v || typeof v !== 'object') return false;
  const c = v as Record<string, unknown>;
  if (typeof c['context'] !== 'object' || typeof c['metadata'] !== 'object') return false;
  const meta = c['metadata'] as Record<string, unknown>;
  // Accept flat metadata.mimeType OR nested metadata.content.mimeType (h5p_player.json format)
  const mimeType =
    typeof meta['mimeType'] === 'string'
      ? meta['mimeType']
      : (meta['content'] && typeof (meta['content'] as Record<string, unknown>)['mimeType'] === 'string')
        ? (meta['content'] as Record<string, unknown>)['mimeType'] as string
        : null;
  return typeof mimeType === 'string';
}
