// ── Sunbird standard event IDs ─────────────────────────────────────────────
// These match the eid field in the Sunbird telemetry v3.0 envelope.

export const SunbirdEID = {
  /** Player opens and content starts loading */
  START: 'START',
  /** User interaction with the player (touch, keyboard, controls) */
  INTERACT: 'INTERACT',
  /** Player session ends after content was fully completed */
  END: 'END',
  /** Player closed before content was completed (user exited early) */
  CLOSE: 'CLOSE',
  /** A page/screen is rendered */
  IMPRESSION: 'IMPRESSION',
  /** Error events */
  ERROR: 'ERROR',
  /** Periodic heartbeat / progress */
  HEARTBEAT: 'HEARTBEAT',
} as const;

export type SunbirdEIDType = (typeof SunbirdEID)[keyof typeof SunbirdEID];

