import type {
  SunbirdPlayerConfig,
  PlayerInitConfig,
  ExtraConfig,
  TelemetryConfig,
  EndScreenConfig,
  ContentMetadata,
} from '../types';

const PLUGIN_END_PAGE = 'org.sunbird.player.endpage';
const PLUGIN_IFRAME_EVENT = 'org.sunbird.iframeEvent';

/**
 * Normalise metadata — handles both shapes:
 *   Flat:   { mimeType, artifactUrl, ... }
 *   Nested: { content: { mimeType, artifactUrl, ... } }   ← h5p_player.json format
 */
function normalizeMetadata(raw: SunbirdPlayerConfig['metadata']): ContentMetadata {
  if (
    raw &&
    typeof raw === 'object' &&
    'content' in raw &&
    raw.content &&
    typeof raw.content === 'object' &&
    typeof (raw.content as Record<string, unknown>)['mimeType'] === 'string'
  ) {
    return raw.content as ContentMetadata;
  }
  return raw;
}

export function adaptSunbirdConfig(
  raw: SunbirdPlayerConfig,
  topLevelExtra?: ExtraConfig
): PlayerInitConfig {
  const { context = {}, config = {} } = raw;
  const metadata = normalizeMetadata(raw.metadata);

  // top-level extra takes precedence over config-embedded extra
  const extra: ExtraConfig = { ...raw.extra, ...topLevelExtra };

  const plugins = config.plugins ?? [];
  const endScreenCapabilityEnabled = plugins.some((p) => p.id === PLUGIN_END_PAGE);
  const iframeEventEnabled = plugins.some((p) => p.id === PLUGIN_IFRAME_EVENT);

  const showEndPage = config.showEndPage !== false;
  const showExit = config.sideMenu?.showExit !== false;
  const showReplay = config.sideMenu?.showReplay !== false;

  const endScreenConfig: EndScreenConfig = {
    exitLabel: showExit ? 'Exit' : undefined,
    showSessionSummary: true,
    showScore: false,
    autoCloseOnComplete: false,
    showReplay,
  };

  // Build full Sunbird telemetry context from the incoming config
  const telemetryConfig: TelemetryConfig = {
    pdata: context.pdata,
    uid: context.uid,
    did: context.did,
    sid: context.sid,                              // user JWT / session token
    channel: context.channel,
    rollup: context.contextRollup ?? {},           // context rollup (l1 = channel/program)
    objectRollup: context.objectRollup ?? {},      // object rollup (course/unit hierarchy)
    tags: context.tags ?? [],
    playerVersion: '2.0',
    env: 'contentplayer',
    ...extra?.telemetry,
  };

  const src =
    (metadata.streamingUrl as string | undefined) ??
    (metadata.artifactUrl as string | undefined) ??
    '';

  const firstName = (context.userData?.firstName ?? context.userdata?.firstname ?? '').trim();
  const lastName  = (context.userData?.lastName  ?? context.userdata?.lastname  ?? '').trim();
  const userName  = [firstName, lastName].filter(Boolean).join(' ') || undefined;

  return {
    contentId: (metadata.identifier as string | undefined) ?? '',
    mimeType: metadata.mimeType,
    src,
    mode: (extra as Record<string, unknown>)['mode'] as 'online' | 'offline' ?? 'online',
    endScreenEnabled: showEndPage,
    endScreenConfig,
    telemetryConfig,
    extra,
    metadata,
    context,
    iframeEventEnabled,
    endScreenCapabilityEnabled,
    userName,
  };
}
