import React, {
  useEffect,
  useRef,
  useCallback,
  forwardRef,
  useImperativeHandle,
  useState,
  type CSSProperties,
} from 'react';
import type { RendererContext } from '@content/player-core';
import { SunbirdEID, H5pInteractId } from '@content/player-core';

// ── xAPI verb constants ──────────────────────────────────────────────────────

const XAPI_VERB = {
  INITIALIZED: 'http://adlnet.gov/expapi/verbs/initialized',
  ANSWERED:    'http://adlnet.gov/expapi/verbs/answered',
  COMPLETED:   'http://adlnet.gov/expapi/verbs/completed',
  PROGRESSED:  'http://adlnet.gov/expapi/verbs/progressed',
  INTERACTED:  'http://adlnet.gov/expapi/verbs/interacted',
  PASSED:      'http://adlnet.gov/expapi/verbs/passed',
  FAILED:      'http://adlnet.gov/expapi/verbs/failed',
  ATTEMPTED:   'http://adlnet.gov/expapi/verbs/attempted',
  EXPERIENCED: 'http://adlnet.gov/expapi/verbs/experienced',
} as const;

const HEADER_HEIGHT = 52;

// ── Types ────────────────────────────────────────────────────────────────────

interface XAPIStatement {
  verb?: { id?: string };
  object?: { id?: string; definition?: { name?: Record<string, string> } };
  result?: {
    completion?: boolean;
    success?: boolean;
    score?: { raw?: number; max?: number; min?: number; scaled?: number };
    duration?: string;
  };
}

export interface H5pRendererHandle {
  getCompletionState(): boolean;
}

interface H5pRendererViewProps {
  context: RendererContext;
  onReady: () => void;
  onStart: () => void;
  onComplete: (score?: number, maxScore?: number, passed?: boolean) => void;
  onError: (message: string) => void;
}

// ── Component ────────────────────────────────────────────────────────────────

export const H5pRendererView = forwardRef<H5pRendererHandle, H5pRendererViewProps>(
  function H5pRendererView({ context, onReady, onStart, onComplete, onError }, ref) {
    const iframeRef             = useRef<HTMLIFrameElement>(null);
    const hasEmittedReady       = useRef(false);
    const hasEmittedComplete    = useRef(false);
    const [iframeSrc, setIframeSrc] = useState<string>('');
    const [muted, setMuted]         = useState(false);

    // ── Theme ──────────────────────────────────────────────────────────────
    const theme   = context.extra?.theme;
    const titleBg = theme?.toolbar   ?? 'rgba(14,14,20,0.97)';
    const accent  = theme?.primary   ?? '#2980b9';
    const pageBg  = theme?.background ?? '#000';

    // Expose imperative handle
    useImperativeHandle(ref, () => ({
      getCompletionState: () => hasEmittedComplete.current,
    }));

    // Build iframe src from h5p content source.
    //
    // OFFLINE MODE (.h5p file):
    //   When context.src ends in ".h5p" or context.extra.h5pFile is set (File or URL),
    //   we pass h5pFile=<url> to h5p-iframe.html which extracts the ZIP in-browser
    //   and serves all content files from memory. Libraries still come from /h5p-libs/.
    //
    // ONLINE MODE (streaming URL):
    //   Sunbird/Knowlg h5p.json lives at {streamingUrl}/content/h5p.json.
    //   h5p-standalone computes contentJsonPath = h5pJsonPath + '/content', so we
    //   pass h5pJsonPath = streamingUrl (no /content). The fetch interceptor retries
    //   {h5pJsonPath}/content/h5p.json when {h5pJsonPath}/h5p.json is missing.
    //   librariesPath is resolved relative to h5p-iframe.html (default: './h5p-libs').
    useEffect(() => {
      const src        = context.src ?? '';
      const h5pFileArg = context.extra?.h5pFile as File | string | undefined;
      const isOffline  = h5pFileArg || src.endsWith('.h5p');

      let cleanupBlobUrl: string | null = null;

      if (!src && !h5pFileArg) {
        onError('No H5P content URL provided (missing streamingUrl / artifactUrl)');
        return;
      }

      const iframePage = new URL('h5p-iframe.html', window.location.href);
      iframePage.searchParams.set('contentId', context.contentId);

      if (isOffline) {
        // Resolve the file URL: accept File object, blob URL, or a plain URL string
        let fileUrl: string;
        if (h5pFileArg instanceof File) {
          fileUrl = URL.createObjectURL(h5pFileArg);
          cleanupBlobUrl = fileUrl;
        } else if (typeof h5pFileArg === 'string') {
          fileUrl = h5pFileArg;
        } else {
          fileUrl = src; // src itself ends in .h5p
        }
        iframePage.searchParams.set('h5pFile', fileUrl);
      } else {
        // Pass streamingUrl as-is (no /content suffix).
        // h5p-standalone constructs contentJsonPath = h5pJsonPath + '/content', so:
        //   h5p.json    → h5pJsonPath/h5p.json          (interceptor falls back to /content/h5p.json for Sunbird S3)
        //   content.json → h5pJsonPath/content/content.json  ← correct for Sunbird S3 layout
        //   media files → h5pJsonPath/content/images/…       ← correct
        const h5pBase = src.replace(/\/+$/, '');
        iframePage.searchParams.set('h5pBase', h5pBase);
      }

      // Only forward librariesPath when explicitly configured — h5p-iframe.html
      // defaults to the relative 'h5p-libs' path which works from any sub-directory.
      const customLibPath = context.extra?.h5p?.librariesPath as string | undefined;
      if (customLibPath) {
        iframePage.searchParams.set('librariesPath', customLibPath);
      }

      setIframeSrc(iframePage.toString());

      return () => {
        if (cleanupBlobUrl) URL.revokeObjectURL(cleanupBlobUrl);
      };
    }, [context.src, context.contentId, context.extra]);

    // ── Mute toggle ────────────────────────────────────────────────────────
    const handleMuteToggle = useCallback(() => {
      const newMuted = !muted;
      setMuted(newMuted);
      context.emit(SunbirdEID.INTERACT, {
        type:    'TOUCH',
        subtype: newMuted ? 'mute' : 'unmute',
        id:      'h5p_mute_toggle',
        pageid:  'h5p-player',
      });
      try {
        iframeRef.current?.contentWindow?.postMessage(
          { context: 'h5p-control', action: 'mute', muted: newMuted },
          '*'
        );
      } catch {
        // cross-origin guard — postMessage should still work for same-origin
      }
    }, [muted, context]);

    // ── Exit handler ───────────────────────────────────────────────────────
    const handleExit = useCallback(() => {
      context.emit(SunbirdEID.INTERACT, {
        type:    'TOUCH',
        subtype: '',
        id:      'h5p_exit_button',
        pageid:  'h5p-player',
      });
      context.onExitRequest?.();
    }, [context]);

    // ── xAPI postMessage bridge ────────────────────────────────────────────
    const handleMessage = useCallback(
      (ev: MessageEvent) => {
        const data = ev.data;
        if (!data || typeof data !== 'object') return;

        // Error notification from iframe
        if (data.context === 'h5p' && data.action === 'error') {
          onError(String(data.message ?? 'H5P load error'));
          return;
        }

        // Resize notification — ignore (h5p-iframe.html handles fit internally)
        if (data.context === 'h5p' && data.action === 'resize') return;

        // xAPI statement from h5p-standalone
        let stmt: XAPIStatement | null = null;
        if (data.type === 'h5p-xapi' && data.statement) {
          stmt = data.statement as XAPIStatement;
        } else if (data.context === 'h5p' && data.action === 'xAPI' && data.statement) {
          stmt = data.statement as XAPIStatement;
        }
        if (!stmt) return;

        processXAPI(stmt);
      },
      // eslint-disable-next-line react-hooks/exhaustive-deps
      []
    );

    function processXAPI(stmt: XAPIStatement) {
      const verbId  = stmt?.verb?.id ?? '';
      const itemId  = stmt?.object?.id ?? '';
      const result  = stmt?.result;

      switch (verbId) {
        case XAPI_VERB.INITIALIZED:
        case XAPI_VERB.ATTEMPTED:
        case XAPI_VERB.EXPERIENCED:
          if (!hasEmittedReady.current) {
            hasEmittedReady.current = true;
            onReady();
            onStart();
            // Emit IMPRESSION telemetry
            context.emit(SunbirdEID.IMPRESSION, {
              type:   'workflow',
              pageid: 'h5p-player',
              uri:    context.contentId,
            });
          }
          break;

        case XAPI_VERB.ANSWERED:
        case XAPI_VERB.INTERACTED:
          // Emit INTERACT telemetry
          context.emit(SunbirdEID.INTERACT, {
            type:    'TOUCH',
            subtype: verbId === XAPI_VERB.ANSWERED ? 'answered' : 'interacted',
            id:      H5pInteractId.XAPI_ANSWERED,
            pageid:  'h5p-player',
            extra: {
              itemId,
              score:    result?.score?.raw,
              maxScore: result?.score?.max,
              success:  result?.success,
            },
          });
          break;

        case XAPI_VERB.PROGRESSED:
          // Emit lightweight heartbeat
          context.emit(SunbirdEID.HEARTBEAT, {
            type:   'h5p-progressed',
            pageid: 'h5p-player',
            itemId,
          });
          break;

        case XAPI_VERB.COMPLETED:
        case XAPI_VERB.PASSED:
        case XAPI_VERB.FAILED:
          if (!hasEmittedComplete.current) {
            hasEmittedComplete.current = true;
            const score    = result?.score?.raw;
            const maxScore = result?.score?.max;
            const passed   = result?.success ?? (verbId === XAPI_VERB.PASSED);
            // Emit INTERACT for submit/complete action
            context.emit(SunbirdEID.INTERACT, {
              type:    'TOUCH',
              subtype: 'completed',
              id:      H5pInteractId.XAPI_COMPLETED,
              pageid:  'h5p-player',
              extra: { score, maxScore, passed, verb: verbId.split('/').pop() },
            });
            onComplete(score, maxScore, passed);
          }
          break;
      }
    }

    useEffect(() => {
      window.addEventListener('message', handleMessage);
      return () => window.removeEventListener('message', handleMessage);
    }, [handleMessage]);

    const handleIframeError = useCallback(() => {
      onError('Failed to load H5P iframe — h5p-iframe.html not found at: ' + iframeSrc);
    }, [iframeSrc, onError]);

    if (!iframeSrc) return null;

    return (
      <div style={wrapperStyle(pageBg)}>

        {/* ── Header bar ──────────────────────────────────────────────────── */}
        <div style={headerStyle(titleBg)}>

          {/* Back / exit button */}
          <button style={headerIconBtnStyle} onClick={handleExit} aria-label="Go back">
            <svg width="20" height="20" viewBox="0 0 24 24" fill="none">
              <path d="M19 12H5M12 5l-7 7 7 7"
                stroke="currentColor" strokeWidth="2"
                strokeLinecap="round" strokeLinejoin="round" />
            </svg>
          </button>

          {/* Title */}
          <div style={headerTitleStyle}>
            {context.contentName ?? 'H5P Content'}
          </div>

          {/* Mute / unmute */}
          <button
            style={headerIconBtnStyle}
            onClick={handleMuteToggle}
            aria-label={muted ? 'Unmute' : 'Mute'}
          >
            {muted ? <MutedIcon accent={accent} /> : <SoundIcon accent={accent} />}
          </button>
        </div>

        {/* ── H5P content iframe ───────────────────────────────────────────── */}
        <iframe
          ref={iframeRef}
          src={iframeSrc}
          title={context.contentName ?? 'H5P Content'}
          style={iframeStyle}
          sandbox="allow-scripts allow-same-origin allow-forms allow-modals allow-popups allow-popups-to-escape-sandbox"
          allow="autoplay; fullscreen"
          onError={handleIframeError}
        />
      </div>
    );
  }
);

// ── Styles ────────────────────────────────────────────────────────────────────

const wrapperStyle = (bg: string): CSSProperties => ({
  display:       'flex',
  flexDirection: 'column',
  width:         '100%',
  height:        '100%',
  background:    bg,
  overflow:      'hidden',
});

const headerStyle = (bg: string): CSSProperties => ({
  height:         HEADER_HEIGHT,
  flexShrink:     0,
  background:     bg,
  backdropFilter: 'blur(8px)',
  display:        'flex',
  alignItems:     'center',
  padding:        '0 4px',
  borderBottom:   '1px solid rgba(255,255,255,0.06)',
  zIndex:         10,
});

const headerIconBtnStyle: CSSProperties = {
  width:           40,
  height:          40,
  flexShrink:      0,
  border:          'none',
  borderRadius:    8,
  background:      'none',
  color:           '#fff',
  display:         'flex',
  alignItems:      'center',
  justifyContent:  'center',
  cursor:          'pointer',
  transition:      'background 0.15s',
};

const headerTitleStyle: CSSProperties = {
  flex:           1,
  textAlign:      'center',
  color:          '#fff',
  fontSize:       15,
  fontWeight:     500,
  fontFamily:     '-apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif',
  whiteSpace:     'nowrap',
  overflow:       'hidden',
  textOverflow:   'ellipsis',
  padding:        '0 8px',
};

const iframeStyle: CSSProperties = {
  flex:    1,
  width:   '100%',
  border:  'none',
  display: 'block',
  minHeight: 0,
};

// ── Icon components ───────────────────────────────────────────────────────────

function SoundIcon({ accent }: { accent: string }) {
  return (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none">
      <path d="M11 5L6 9H2v6h4l5 4V5z"
        fill={accent} />
      <path d="M19.07 4.93a10 10 0 0 1 0 14.14M15.54 8.46a5 5 0 0 1 0 7.07"
        stroke={accent} strokeWidth="2" strokeLinecap="round" />
    </svg>
  );
}

function MutedIcon({ accent }: { accent: string }) {
  void accent;
  return (
    <svg width="20" height="20" viewBox="0 0 24 24" fill="none">
      <path d="M11 5L6 9H2v6h4l5 4V5z"
        fill="rgba(255,255,255,0.4)" />
      <line x1="23" y1="9" x2="17" y2="15"
        stroke="rgba(255,255,255,0.6)" strokeWidth="2" strokeLinecap="round" />
      <line x1="17" y1="9" x2="23" y2="15"
        stroke="rgba(255,255,255,0.6)" strokeWidth="2" strokeLinecap="round" />
    </svg>
  );
}
