import React from 'react';
import { createRoot, type Root } from 'react-dom/client';
import {
  adaptSunbirdConfig,
  isSunbirdPlayerConfig,
  type SunbirdPlayerConfig,
  type PlayerInitConfig,
  type ExtraConfig,
  type ContentMetadata,
} from '@content/player-core';
import { PlayerShell } from '@content/player-shell';
import { rendererSelector } from './rendererSelector';

const PLAYER_EVENTS = [
  'player:ready',
  'player:start',
  'player:progress',
  'player:complete',
  'player:endscreen',
  'player:error',
  'player:close',
] as const;

type PlayerEventName = (typeof PLAYER_EVENTS)[number];

export class ContentPlayerElement extends HTMLElement {
  private shadowRoot_!: ShadowRoot;
  private mountPoint!: HTMLDivElement;
  private root: Root | null = null;
  private _sunbirdPlayerConfig: SunbirdPlayerConfig | null = null;
  private _metadata: Partial<ContentMetadata> | null = null;
  private _extra: ExtraConfig | null = null;
  private _playerConfig: PlayerInitConfig | null = null;
  /** Incremented on every config assignment so the key always changes, forcing a full remount. */
  private _configVersion = 0;

  static get observedAttributes(): string[] {
    return ['mode', 'mime-type', 'src', 'content-id', 'player-version'];
  }

  connectedCallback(): void {
    this.shadowRoot_ = this.attachShadow({ mode: 'open' });

    // Inject reset styles into shadow DOM
    const style = document.createElement('style');
    style.textContent = `
      :host { display: block; width: 100%; height: 100%; }
      * { box-sizing: border-box; margin: 0; padding: 0; }
      @keyframes spin { to { transform: rotate(360deg); } }
    `;
    this.shadowRoot_.appendChild(style);

    this.mountPoint = document.createElement('div');
    this.mountPoint.style.cssText = 'width:100%;height:100%;';
    this.shadowRoot_.appendChild(this.mountPoint);

    this.root = createRoot(this.mountPoint);
    this.scheduleRender();
  }

  disconnectedCallback(): void {
    this.root?.unmount();
    this.root = null;
  }

  attributeChangedCallback(): void {
    this.scheduleRender();
  }

  set sunbirdPlayerConfig(val: unknown) {
    if (!isSunbirdPlayerConfig(val)) {
      console.warn('[ContentPlayer] Invalid sunbirdPlayerConfig — expected { context, metadata }');
      return;
    }
    this._sunbirdPlayerConfig = val;
    this._configVersion++;
    this.scheduleRender();
  }

  get sunbirdPlayerConfig(): SunbirdPlayerConfig | null {
    return this._sunbirdPlayerConfig;
  }

  set metadata(val: Partial<ContentMetadata>) {
    this._metadata = val;
    this.scheduleRender();
  }

  set extra(val: ExtraConfig) {
    this._extra = val;
    this.scheduleRender();
  }

  set playerConfig(val: PlayerInitConfig) {
    this._playerConfig = val;
    this.scheduleRender();
  }

  // ── Private ───────────────────────────────────────────────────────────────

  private _renderPending = false;

  private scheduleRender(): void {
    if (this._renderPending) return;
    this._renderPending = true;
    Promise.resolve().then(() => {
      this._renderPending = false;
      this.render();
    });
  }

  private buildConfig(): PlayerInitConfig | null {
    if (this._playerConfig) return this._playerConfig;

    if (!this._sunbirdPlayerConfig) return null;

    const merged: SunbirdPlayerConfig = {
      ...this._sunbirdPlayerConfig,
      metadata: {
        ...this._sunbirdPlayerConfig.metadata,
        ...(this._metadata ?? {}),
      } as ContentMetadata,
    };

    // Apply mode attribute if provided
    const modeAttr = this.getAttribute('mode') as 'online' | 'offline' | null;
    const extra: ExtraConfig = {
      ...(this._extra ?? {}),
      ...(modeAttr ? ({ mode: modeAttr } as ExtraConfig) : {}),
    };

    return adaptSunbirdConfig(merged, extra);
  }

  private render(): void {
    if (!this.root) return;

    const config = this.buildConfig();
    if (!config) return;

    const renderer = rendererSelector(config.mimeType);
    if (!renderer) {
      this.dispatchPlayerEvent('player:error', {
        message: `Unsupported content type: ${config.mimeType}`,
        mimeType: config.mimeType,
      });
      return;
    }

    this.root.render(
      React.createElement(PlayerShell, {
        key: `${config.contentId || config.mimeType}-v${this._configVersion}`,
        config,
        renderer,
        onEvent: (event: string, detail: unknown) => {
          if (PLAYER_EVENTS.includes(event as PlayerEventName)) {
            this.dispatchPlayerEvent(event as PlayerEventName, detail);
          } else if (event === 'playerTelemetryEvent') {
            this.dispatchEvent(
              new CustomEvent('playerTelemetryEvent', {
                detail,
                bubbles: true,
                composed: true,
              })
            );
          }
        },
      })
    );
  }

  private dispatchPlayerEvent(eventName: string, detail: unknown): void {
    this.dispatchEvent(
      new CustomEvent(eventName, {
        detail,
        bubbles: true,
        composed: true, // crosses shadow DOM boundary
      })
    );
  }
}
