import { createRoot, type Root } from 'react-dom/client';
import React, { createRef } from 'react';
import type { RendererInterface, RendererContext, PlayerEvent } from '@content/player-core';
import { H5pRendererView, type H5pRendererHandle } from './H5pRendererView';

/**
 * H5pRenderer implements RendererInterface.
 *
 * It mounts H5pRendererView (a React component with a sandboxed iframe)
 * into whatever container PlayerShell provides.
 *
 * H5P content is loaded inside the iframe via h5p-standalone.
 * xAPI statements from H5P are bridged via postMessage → renderer events.
 *
 * Telemetry flow (delegated to PlayerShell via RendererInterface events):
 *   xAPI initialized/attempted → player:ready + player:start
 *       → PlayerShell emits SunbirdEID.START
 *   xAPI completed/passed/failed → player:complete
 *       → PlayerShell emits SunbirdEID.END
 *   User exits → PlayerShell emits SunbirdEID.END (via triggerClose)
 */
export class H5pRenderer implements RendererInterface {
  private root: Root | null = null;
  private handleRef = createRef<H5pRendererHandle>();
  private handlers  = new Map<PlayerEvent, Set<(payload: unknown) => void>>();
  private context: RendererContext | null = null;

  // H5P manages its own end screen (score / pass-fail summary in the iframe)
  // so we ask PlayerShell to show its generic EndScreen as well for session summary
  readonly hasOwnEndScreen = false;

  on(event: PlayerEvent, handler: (payload: unknown) => void): void {
    if (!this.handlers.has(event)) this.handlers.set(event, new Set());
    this.handlers.get(event)!.add(handler);
  }

  removeAllListeners(): void {
    this.handlers.clear();
  }

  async mount(container: HTMLElement, context: RendererContext): Promise<void> {
    this.context = context;
    this.root    = createRoot(container);

    this.root.render(
      React.createElement(H5pRendererView, {
        ref: this.handleRef,
        context,
        onReady:    () => this.fire('player:ready', {}),
        onStart:    () => this.fire('player:start', {}),
        onComplete: (score?: number, maxScore?: number, passed?: boolean) =>
          this.fire('player:complete', { score, maxScore, passed }),
        onError:    (message: string) => this.fire('player:error', { message }),
      })
    );
  }

  async unmount(): Promise<void> {
    this.root?.unmount();
    this.root = null;
  }

  getCurrentPosition(): number {
    // H5P does not expose a meaningful linear position — return 0
    return 0;
  }

  seek(_position: number | string): void {
    // H5P does not support external seeking
  }

  getCompletionState(): boolean {
    return this.handleRef.current?.getCompletionState() ?? false;
  }

  private fire(event: PlayerEvent, payload: unknown): void {
    this.handlers.get(event)?.forEach((h) => h(payload));
  }
}
